import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom', isFast?: boolean) => void;
  onClose: () => void;
  isARMode: boolean;
  toggleARMode: () => void;
}

export const GestureController: React.FC<GestureControllerProps> = ({ 
  onControl, 
  onClose,
  isARMode,
  toggleARMode
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  // State for zoom and speed logic
  const prevHandDistanceRef = useRef<number | null>(null);
  const prevHandXRef = useRef<number | null>(null);
  const lastTimeRef = useRef<number>(0);

  // UI State
  const [statusMessage, setStatusMessage] = useState<string>("启动魔法手势...");

  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 2
        });

        if (isMounted) startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) {
          setLoading(false);
          setStatusMessage("初始化失败");
        }
      }
    };

    init();

    return () => {
      isMounted = false;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          width: { ideal: 640 },
          height: { ideal: 480 },
          facingMode: "user" 
        } 
      });

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }

      setLoading(false);
      setStatusMessage("准备好了！");
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
      setStatusMessage("无法打开摄像头");
    }
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current) return;

    if (videoRef.current.readyState < 2) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    const result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);

    processGestures(result);
    if (canvasRef.current) {
        draw(result);
    }

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult) => {
    const hands = result.landmarks;
    const now = performance.now();
    const dt = (now - lastTimeRef.current) / 1000;
    lastTimeRef.current = now;

    if (!hands || hands.length === 0) {
      onControl(0, 0, 'rotate');
      prevHandDistanceRef.current = null;
      prevHandXRef.current = null;
      setStatusMessage("挥挥手开始控制");
      return;
    }

    // --- 双手模式 (缩放) ---
    // 要求：减少距离 -> 拉远镜头 (Zoom Out), 增加距离 -> 拉近镜头 (Zoom In)
    if (hands.length === 2) {
      prevHandXRef.current = null; // 重置单手状态
      const h1 = hands[0][9]; 
      const h2 = hands[1][9];
      const dist = Math.hypot(h1.x - h2.x, h1.y - h2.y);

      if (prevHandDistanceRef.current !== null) {
        const delta = dist - prevHandDistanceRef.current;

        if (Math.abs(delta) > 0.001) {
           // delta > 0 表示距离增加 -> 应该 Zoom In (拉近)
           // delta < 0 表示距离减少 -> 应该 Zoom Out (拉远)
           onControl(0, delta * 300, 'zoom'); 

           if (delta > 0) setStatusMessage("🔍 放大 (增加距离)");
           else setStatusMessage("🔭 缩小 (减少距离)");
        } else {
           onControl(0, 0, 'zoom');
           setStatusMessage("✋ 双手保持距离");
        }
      }
      prevHandDistanceRef.current = dist;
      return;
    }

    // --- 单手模式 (旋转) ---
    // 要求：删除下移逻辑，增加快速移动时的 10 倍速逻辑
    if (hands.length === 1) {
      prevHandDistanceRef.current = null; // 重置双手状态
      const hand = hands[0];
      const cursor = hand[9]; 

      const x = 1.0 - cursor.x; // 镜像逻辑

      let dx = 0;
      const DEADZONE = 0.15;
      const CENTER = 0.5;

      // 检测移动速度 (用于 10x 逻辑)
      let isFast = false;
      if (prevHandXRef.current !== null && dt > 0) {
          const speedX = Math.abs(x - prevHandXRef.current) / dt;
          if (speedX > 1.2) { // 快速移动阈值
              isFast = true;
          }
      }
      prevHandXRef.current = x;

      // 水平旋转控制
      if (Math.abs(x - CENTER) > DEADZONE) {
         dx = (x - CENTER) * 2.0; 
      }

      if (dx !== 0) {
        onControl(dx, 0, 'rotate', isFast);

        let msg = dx > 0 ? "👉 向右旋转" : "👈 向左旋转";
        if (isFast) msg = "⚡ 快速" + msg;
        setStatusMessage(msg);
      } else {
        onControl(0, 0, 'rotate');
        setStatusMessage("✋ 居中暂停");
      }
    }
  };

  const draw = (result: HandLandmarkerResult) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (!isARMode && videoRef.current) {
        ctx.save();
        ctx.scale(-1, 1);
        ctx.drawImage(videoRef.current, -canvas.width, 0, canvas.width, canvas.height);
        ctx.restore();

        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.lineWidth = 2;
        ctx.setLineDash([5, 5]);
        const deadzoneSize = 0.3; 
        const x = canvas.width * (0.5 - deadzoneSize/2);
        const y = canvas.height * (0.5 - deadzoneSize/2);
        const w = canvas.width * deadzoneSize;
        const h = canvas.height * deadzoneSize;
        ctx.strokeRect(x, y, w, h);
        ctx.setLineDash([]);
    }

    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        const connections = HandLandmarker.HAND_CONNECTIONS;
        ctx.strokeStyle = "#00ffff";
        ctx.lineWidth = 3;

        for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          ctx.beginPath();
          ctx.moveTo((1 - start.x) * canvas.width, start.y * canvas.height);
          ctx.lineTo((1 - end.x) * canvas.width, end.y * canvas.height);
          ctx.stroke();
        }

        ctx.fillStyle = "#ff00ff";
        for (const lm of landmarks) {
           ctx.beginPath();
           ctx.arc((1 - lm.x) * canvas.width, lm.y * canvas.height, 4, 0, 2 * Math.PI);
           ctx.fill();
        }
      }
    }
  };

  return (
    <>
      <video 
        ref={videoRef} 
        className={`fixed inset-0 w-full h-full object-cover -scale-x-100 transition-opacity duration-300
          ${isARMode ? 'z-[-10] opacity-100' : 'z-[-20] opacity-0 pointer-events-none'}
        `}
        autoPlay 
        playsInline 
        muted
        onLoadedData={() => {
            predictWebcam();
        }}
      />

      {/* AR模式 蓝黑色遮罩 0.4 透明度 */}
      {isARMode && (
         <div className="fixed inset-0 w-full h-full bg-[#000814]/40 z-[-9] pointer-events-none transition-colors duration-500" />
      )}

      <canvas 
        ref={canvasRef}
        width={320}
        height={240}
        className={`fixed bottom-20 right-4 w-40 h-32 rounded-lg border-2 border-white/20 shadow-lg z-50 bg-black/50 pointer-events-none transition-opacity duration-300
           ${isARMode ? 'opacity-0' : 'opacity-100'}
        `}
      />

      <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 pointer-events-auto animate-fade-in">
        <div className="bg-slate-900/80 backdrop-blur border border-cyan-500/30 text-cyan-300 px-4 py-2 rounded-full font-bold shadow-lg flex items-center gap-2">
           <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400' : 'bg-green-400'} animate-pulse`}></span>
           {statusMessage}
        </div>

        {permissionError && (
           <div className="bg-red-500/80 text-white px-4 py-2 rounded-lg text-sm max-w-[200px]">
              请允许浏览器访问摄像头以使用手势功能。
           </div>
        )}

        <div className="flex items-center gap-3">
           <button 
             onClick={toggleARMode}
             disabled={loading || permissionError}
             className={`h-12 px-5 rounded-full font-bold text-sm shadow-lg border-2 transition-all flex items-center gap-2
               ${isARMode 
                 ? 'bg-cyan-500 text-black border-cyan-200 shadow-[0_0_15px_#22d3ee]' 
                 : 'bg-slate-800 text-white border-slate-600 hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed'
               }`}
           >
             <span>{isARMode ? "📺 关闭画面" : "📹 显示画面 (AR)"}</span>
           </button>

           <button 
              onClick={onClose}
              className="w-12 h-12 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white/20 active:scale-95 transition-all"
           >
              ✕
           </button>
        </div>
      </div>
    </>
  );
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping, MathUtils } from 'three';
import { PLANETS, SUN_DATA, JUPITER_MOONS, SATURN_MOONS, MOON_DATA, TIANGONG_DATA } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; 
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0001;
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

const CameraFlyTo = ({ target, planetRefs, controlsRef, setTarget }: { target: { id: string, size: number } | null, planetRefs: any, controlsRef: any, setTarget: any }) => {
  useFrame((state, delta) => {
    if (!target) return;
    const { id, size } = target;
    const targetObj = planetRefs.current[id];

    if (!targetObj) {
      setTarget(null);
      return;
    }

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);

    const currentCamPos = state.camera.position.clone();
    const dir = new Vector3().subVectors(currentCamPos, targetPos).normalize();
    const zoomDist = Math.max(size * 4, 6.0); 
    const desiredCamPos = targetPos.clone().add(dir.multiplyScalar(zoomDist));

    const lerpFactor = 4.0 * delta;
    controlsRef.current.target.lerp(targetPos, lerpFactor);
    state.camera.position.lerp(desiredCamPos, lerpFactor);
    controlsRef.current.update();

    if (state.camera.position.distanceTo(desiredCamPos) < 0.5 && 
        controlsRef.current.target.distanceTo(targetPos) < 0.1) {
       setTarget(null);
    }
  });
  return null;
}

const OrbitController = ({ controlsRef, gestureState }: { controlsRef: any, gestureState: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom', isFast: boolean}> }) => {
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType, isFast } = gestureState.current;

      const smoothFactor = 6.0 * delta;
      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);

      const threshold = 0.0005; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;

      if (activeDx !== 0 || activeDy !== 0) {
          if (gestureType === 'rotate') {
             // 旋转逻辑：如果有 isFast 标志，应用 10 倍速
             const speedMultiplier = isFast ? 0.3 : 0.03;
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * speedMultiplier);

             // 删除垂直方向旋转逻辑
          } else if (gestureType === 'zoom') {
             const zoomSensitivity = 0.02;
             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);

             if (activeDy > 0) {
                 controlsRef.current.dollyIn(speed);
             } else {
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); 

  const [focusTarget, setFocusTarget] = useState<{ id: string, size: number } | null>(null);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureState = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom', isFast: boolean}>({ 
    dx: 0, 
    dy: 0, 
    gestureType: 'rotate', 
    isFast: false 
  });

  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  const getPlanetSize = (id: string): number => {
      if (id === 'sun') return SUN_DATA.size;
      if (id === 'moon') return MOON_DATA.size;
      if (id === 'tiangong') return TIANGONG_DATA.size;

      const p = PLANETS.find(x => x.id === id);
      if (p) return p.size;

      const jm = JUPITER_MOONS.find(x => x.id === id);
      if (jm) return jm.size;

      const sm = SATURN_MOONS.find(x => x.id === id);
      if (sm) return sm.size;

      return 2;
  };

  const handleDoubleClick = (id: string) => {
      const size = getPlanetSize(id);
      setFocusTarget({ id, size });
      handleSelect(id);
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const toggleOrbits = () => {
    setShowOrbits(!showOrbits);
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom', isFast?: boolean) => {
    gestureState.current = { dx, dy, gestureType, isFast: !!isFast };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
       setFocusTarget(null);
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    if (selectedPlanetId === 'moon') return MOON_DATA;
    if (selectedPlanetId === 'tiangong') return TIANGONG_DATA;
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    const jMoon = JUPITER_MOONS.find(m => m.id === selectedPlanetId);
    if (jMoon) return jMoon;
    return SATURN_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >
      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
        showOrbits={showOrbits}
        toggleOrbits={toggleOrbits}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      <Canvas 
        gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}
        onPointerMissed={() => {
          if (selectedPlanetId) {
            handleClose();
          }
        }}
      >
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={2}
            maxDistance={500}
            maxPolarAngle={Math.PI / 1.8}
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive && !focusTarget}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <CameraFlyTo 
             target={focusTarget} 
             planetRefs={planetRefs} 
             controlsRef={controlsRef} 
             setTarget={setFocusTarget} 
          />

          <OrbitController controlsRef={controlsRef} gestureState={gestureState} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />
          {!isARMode && <Skybox />}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             onDoubleClick={handleDoubleClick}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
             planetRefs={planetRefs}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              onDoubleClick={handleDoubleClick}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
              showOrbit={showOrbits}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}
        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;
